package dev.codedefense.application;
import static org.junit.jupiter.api.Assertions.*;import dev.codedefense.change.*;import dev.codedefense.domain.*;import dev.codedefense.passport.*;import java.nio.file.*;import java.time.Instant;import java.util.*;import org.junit.jupiter.api.*;import org.junit.jupiter.api.io.TempDir;
class VerifyLatestGitChangePassportUseCaseTest {@TempDir Path directory;
 @Test void verifiesCommitReceiptWithTypedSelector(){PassportReceipt base=PassportReceipt.from(PassportTestFixtures.passport(PassportStatus.CURRENT),"11111111-1111-4111-8111-111111111111");PassportReceipt receipt=new PassportReceipt(3,base.receiptId(),base.repositoryIdentityHash(),ChangeKind.COMMIT,base.baseCommit(),"e".repeat(40),base.diffFingerprint(),base.createdAt(),base.statusAtCreation(),base.files(),base.categories(),base.overallScore(),base.readiness(),base.skippedPrimaryCount(),base.model(),base.attemptId(),base.supersedes(),base.attemptNumber(),base.focus());StoredChangePassport stored=new StoredChangePassport(directory.resolve("a.md"),directory.resolve("a.json"),receipt);ChangePassportStore store=new ChangePassportStore(){public Path save(ChangePassport p){throw new AssertionError();}public Optional<StoredPassportIdentity> readLatestIdentity(){return Optional.empty();}public Optional<StoredChangePassport> readLatest(){return Optional.of(stored);}};GitChangeSource source=new GitChangeSource(){public CapturedGitChange capture(Path p,ChangeSelector s){throw new AssertionError();}public GitChangeIdentity captureIdentity(Path p,ChangeSelector selector){assertInstanceOf(CommitSelector.class,selector);return new GitChangeIdentity(ChangeKind.COMMIT,receipt.baseCommit(),receipt.sourceIdentity(),receipt.diffFingerprint());}};assertEquals(PassportStatus.CURRENT,new VerifyLatestGitChangePassportUseCase(source,store).verify(directory).orElseThrow().status());}
}
